mapper.select:
SELECT a.id as paperId, a.title, count(IF(b.status = 0, a.id, NULL)) AS `unApproveCount`, count(IF(b.status = 1, a.id, NULL)) AS `approvedCount` FROM collect_paper a LEFT JOIN collect_paper_submit b ON (a.id = b.paper_id and a.is_delete=0 and b.is_delete = 0) WHERE a.is_delete=0 and a.id IN
#{item}
GROUP BY a.id ORDER BY a.update_time DESC

select pa.*, ap.user as approver from collect_paper pa left join collect_paper_approver ap on (pa.id=ap.paper_id and pa.is_delete=0 and ap.is_delete=0) where pa.project_id = #{projectId} and pa.create_by = #{username} and pa.is_delete=0
and pa.title like #{pattern}
order by pa.update_time desc LIMIT #{start},#{end}

mapper.update:
update collect_paper set status = #{status}
where is_delete=0 AND id in

    #{item}
